import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Determine the maximum size for the buffer
        int bufferSize = Math.min(name.length(), 10);

        // Create a fixed-size buffer to store the user input
        char[] buffer = new char[bufferSize];

        // Copy the user input into the buffer without exceeding its length
        name.getChars(0, bufferSize, buffer, 0);

        // Print out the content of the buffer
        System.out.println("Buffer content: " + new String(buffer));
    }
}

